mapper.select:
SELECT qf.*, u.nickname AS user_name, wo.product_name AS work_order_product_name FROM quality_feedback qf LEFT JOIN user u ON qf.user_id = u.id LEFT JOIN work_order wo ON qf.work_order_id = wo.id
AND qf.user_id = #{userId} AND qf.status = #{status}
ORDER BY qf.create_time DESC

mapper.update:
UPDATE quality_feedback
status = #{status}, reply = #{reply},
WHERE id = #{id}
